SET client_encoding TO 'UTF8';

SET check_function_bodies = false;





CREATE OR REPLACE FUNCTION fpa_lon_req_coll_amt (as_reqno char) RETURNS varchar AS $body$
DECLARE

ls_result varchar(400);
ls_amount bigint := 0;
ls_type sc_lon_m_ucf_collateral_type.collateral_type_code%type;
li_count integer;

type tabrowi_reqcoll is table of sc_lon_m_req_coll%rowtype index by integer;
ltabrowi_reqcoll tabrowi_reqcoll;

BEGIN
   select * bulk collect into STRICT ltabrowi_reqcoll from sc_lon_m_req_coll where loan_requestment_no = as_reqno;
   li_count := ltabrowi_reqcoll.count;
   if li_count > 0 then
    for i in 1..li_count loop

      case ltabrowi_reqcoll[i].collateral_type_code
      when '02' then
        ls_amount := ls_amount + ltabrowi_reqcoll[i].req_amount;
        ls_result := 'หุ้นค้ำ '||to_char(ls_amount,'999,999.99');
      when '03' then
        ls_amount := ls_amount + ltabrowi_reqcoll[i].req_amount;
        ls_result := 'เงินฝากค้ำ '||to_char(ls_amount,'999,999.99');
      else
        return null;
      end case;
    end loop;
   end if;

  return  ls_result;
  exception when others then CALL spa_dberror('E30 : หายอดค้ำประกัน');

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
